// 研究主題(換成你的題目)。WF-9 是『探索型』:會撈出你還不知道的論文,
// 不像 WF-4/7 只驗證你已有的一筆引用。
return [{ json: { query: 'shared-context false pass multi-agent code generation verification', per_page: 5 } }];

// OpenAlex 免金鑰、涵蓋頂級期刊/會議(IEEE/ACM/Springer/Elsevier),比 arXiv 廣得多。
// 取被引數最高的前 N 筆當『頂級候選』,保留 DOI 與 OA 全文連結。
const r = ($json.results) || [];
if (!r.length) return [{ json: { _empty: true, note: 'OpenAlex no results — try another query' } }];
return r.slice(0, ($('Topic').first().json.per_page)||5).map(function(w){
  const doi = (w.doi||'').replace('https://doi.org/','');
  const venue = (w.primary_location && w.primary_location.source && w.primary_location.source.display_name)
             || (w.host_venue && w.host_venue.display_name) || '(unknown venue)';
  const oa = (w.open_access && w.open_access.oa_url) || '';
  return { json: {
    title: w.display_name, year: w.publication_year, venue: venue,
    cited_by: w.cited_by_count, doi: doi,
    is_oa: !!(w.open_access && w.open_access.is_oa), oa_url: oa
  }};
});

// 對齊探索結果(Rank+Screen)與 DOI 驗活結果(本節點輸入),逐筆出『閘判定』。
// 紅線:探索 agent 可能幻覺或讀錯結論 → 任何一筆都『預設不可引用』,
//       必須再過『全文閱讀 + DOI 驗活 + 人類複核』才放行(對應 ALE L1 引文反向教訓)。
const cands = $('Rank + Screen').all();
return $input.all().map(function(it, i){
  const c = (cands[i] && cands[i].json) || {};
  const httpErr = it.json && it.json.error;
  const doi_live = !!c.doi && !httpErr;
  return { json: {
    title: c.title, year: c.year, venue: c.venue, cited_by: c.cited_by,
    doi: c.doi || null, doi_live: doi_live,
    is_oa: c.is_oa, oa_url: c.oa_url || null,
    gate: {
      can_cite: false,
      needs_fulltext_read: true,
      human_review_required: true,
      reason: 'discovery may hallucinate or misread conclusions; cite only after full-text read + DOI live + human review'
    }
  }};
});
